import fs from 'fs-extra';
import { resolve } from 'node:path';
import { BrowserConfigSchema } from './schema.js';
export async function loadBrowserConfig(cwd = process.cwd()) {
    const path = resolve(cwd, 'browser.config.json');
    let value;
    try {
        value = await fs.readJson(path);
    }
    catch (error) {
        throw new Error(`Cannot read ${path}: ${error instanceof Error ? error.message : String(error)}`);
    }
    const parsed = BrowserConfigSchema.safeParse(value);
    if (!parsed.success) {
        const details = parsed.error.issues
            .map((issue) => `${issue.path.join('.')}: ${issue.message}`)
            .join('\n');
        throw new Error(`Invalid browser.config.json:\n${details}`);
    }
    return parsed.data;
}
